async function seed() {
  console.log('Seeding glossary terms...')
  const { error } = await supabase.from('glossary_terms').upsert(terms, { onConflict: 'slug' })
  if (error) { console.error('glossary error:', error.message, error.details); process.exit(1) }
  console.log(`  ✓ ${terms.length} glossary terms seeded`)
  console.log('\nDone.')
}

seed()
